$root = 'C:/Users/enzo1/PROJEC CDX'
$outDir = Join-Path $root 'outputs/sdu-environment-audit'
New-Item -ItemType Directory -Force -Path $outDir | Out-Null

function Safe($scriptBlock, $fallback) {
  try { & $scriptBlock } catch { $fallback }
}

$report = [ordered]@{
  timestamp = (Get-Date).ToString('o')
  computer = [ordered]@{
    hostname = $env:COMPUTERNAME
    user = $env:USERNAME
    userprofile = $env:USERPROFILE
    elevated = ((whoami /groups) -join /"`n/") -match 'Mandatory Label/High Mandatory Level'
  }
  powershell = [ordered]@{
    psversiontable = $PSVersionTable
    execution_policy = Safe { Get-ExecutionPolicy -List } @()
    modules = Safe { Get-Module | Select-Object Name, Version, Path } @()
    aliases = Safe { Get-Alias | Select-Object Name, Definition } @()
    profiles = @(
      $PROFILE,
      $PROFILE.AllUsersAllHosts,
      $PROFILE.AllUsersCurrentHost,
      $PROFILE.CurrentUserAllHosts,
      $PROFILE.CurrentUserCurrentHost
    )
  }
  environment = [ordered]@{
    all = Safe { Get-ChildItem Env: | Sort-Object Name | Select-Object Name, Value } @()
    codex = Safe { Get-ChildItem Env: | Where-Object Name -like 'CODEX_*' | Sort-Object Name | Select-Object Name, Value } @()
    path = ($env:Path -split ';' | Where-Object { $_ })
    pythonpath = $env:PYTHONPATH
  }
  users = [ordered]@{
    whoami_all = Safe { (whoami /all | Out-String).TrimEnd() } ''
    profiles = Safe { Get-CimInstance Win32_UserProfile | Select-Object LocalPath, SID, Loaded, Special } @()
    acl_userprofile = Safe { Get-Acl $env:USERPROFILE | Select-Object Owner, AccessToString } $null
    acl_codex = Safe { Get-Acl (Join-Path $env:USERPROFILE '.codex') | Select-Object Owner, AccessToString } $null
  }
  codex = [ordered]@{
    home_exists = Test-Path (Join-Path $env:USERPROFILE '.codex')
    entries = Safe { Get-ChildItem -LiteralPath (Join-Path $env:USERPROFILE '.codex') -Force | Select-Object Name, FullName, Mode, LastWriteTime } @()
    config_toml = Safe { Get-Content -LiteralPath (Join-Path $env:USERPROFILE '.codex/config.toml') -Raw } $null
  }
  system = [ordered]@{
    computerinfo = Safe { Get-ComputerInfo | Select-Object WindowsProductName, WindowsVersion, OsHardwareAbstractionLayer } $null
    timezone = Safe { Get-TimeZone | Select-Object Id, DisplayName } $null
    drives = Safe { Get-CimInstance Win32_LogicalDisk | Select-Object DeviceID, FileSystem, Size, FreeSpace } @()
    volumes = Safe { Get-Volume | Select-Object DriveLetter, FileSystem, SizeRemaining, Size } @()
  }
  tasks = [ordered]@{
    all = Safe { Get-ScheduledTask -ErrorAction SilentlyContinue | Select-Object TaskName, TaskPath, State } @()
    sdu_like = Safe { Get-ScheduledTask -ErrorAction SilentlyContinue | Where-Object { $_.TaskName -match 'SDU|Codex|PowerShell|Python|Node|Git' } | Select-Object TaskName, TaskPath, State } @()
  }
  services = [ordered]@{
    all = Safe { Get-Service | Select-Object Name, DisplayName, Status, StartType } @()
    relevant = Safe { Get-Service | Where-Object { $_.Name -match 'Codex|Python|Node|Git|W32Time|WinRM' } | Select-Object Name, DisplayName, Status, StartType } @()
  }
  processes = [ordered]@{
    all = Safe { Get-Process | Select-Object Name, Id, Path } @()
    relevant = Safe { Get-Process pwsh,powershell,python,node,cmd,Code -ErrorAction SilentlyContinue | Select-Object Name, Id, Path, StartTime } @()
    tree = Safe { Get-CimInstance Win32_Process | Select-Object ProcessId, ParentProcessId, Name, ExecutablePath, CommandLine } @()
  }
}

$jsonPath = Join-Path $outDir 'sdu-environment-audit-medium.json'
$txtPath = Join-Path $outDir 'sdu-environment-audit-medium.txt'
$report | ConvertTo-Json -Depth 8 | Set-Content -LiteralPath $jsonPath -Encoding UTF8
@(
  'SDU Environment Audit (medium session)'
  /"Timestamp: $($report.timestamp)/"
  /"Elevated: $($report.computer.elevated)/"
) -join /"`r`n/" | Set-Content -LiteralPath $txtPath -Encoding UTF8
Write-Host /"OK -> $jsonPath/"
Write-Host /"OK -> $txtPath
